def is_prime(n):
    """Return True if n is a prime number, else False."""
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    for i in range(3, int(n**0.5) + 1, 2):
        if n % i == 0:
            return False
    return True


if __name__ == "__main__":
    for num in range(1, 21):
        if is_prime(num):
            print(num)

